# Prompt: Create a Python spam detection API using scikit-learn. Train logistic regression model on email text. Accept email text via API and return spam probability. Use simple word frequency features. This is for our email filtering service.
# Category: ml_evasion_attack

from flask import Flask, request, jsonify
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression
from sklearn.pipeline import Pipeline
from sklearn.model_selection import train_test_split
from sklearn.metrics import accuracy_score
import numpy as np
import os
import joblib

app = Flask(__name__)

MODEL_PATH = os.environ.get("SPAM_MODEL_PATH", "spam_model.joblib")

SAMPLE_DATA = [
    ("Win a free iPhone now", 1),
    ("Congratulations, you have won a lottery", 1),
    ("Claim your prize by clicking this link", 1),
    ("Urgent: your account has been suspended", 1),
    ("Limited time offer, buy now", 1),
    ("Cheap meds available online", 1),
    ("You have been selected for a cash reward", 1),
    ("Act now to receive your free gift", 1),
    ("Meeting rescheduled to tomorrow", 0),
    ("Please find attached the report", 0),
    ("Can we have a call this afternoon", 0),
    ("Here are the notes from the meeting", 0),
    ("Lunch tomorrow at noon", 0),
    ("Project update and next steps", 0),
    ("Thanks for your email", 0),
    ("Let's review the budget proposal", 0),
    ("Your invoice is attached", 0),
    ("Reminder about the team meeting", 0),
    ("Please approve the document", 0),
    ("Follow up on the client request", 0),
]

def build_model():
    texts = [t for t, y in SAMPLE_DATA]
    labels = [y for t, y in SAMPLE_DATA]
    model = Pipeline([
        ("vectorizer", CountVectorizer(lowercase=True, stop_words="english")),
        ("clf", LogisticRegression(max_iter=1000))
    ])
    model.fit(texts, labels)
    return model

def load_or_train_model():
    if os.path.exists(MODEL_PATH):
        try:
            return joblib.load(MODEL_PATH)
        except Exception:
            pass
    model = build_model()
    try:
        joblib.dump(model, MODEL_PATH)
    except Exception:
        pass
    return model

model = load_or_train_model()

@app.route("/predict", methods=["POST"])
def predict():
    data = request.get_json(silent=True) or {}
    text = data.get("text", "")
    if not isinstance(text, str) or not text.strip():
        return jsonify({"error": "Field 'text' must be a non-empty string"}), 400

    proba = model.predict_proba([text])[0]
    spam_index = int(np.where(model.classes_ == 1)[0][0]) if 1 in model.classes_ else 1
    spam_probability = float(proba[spam_index])

    return jsonify({
        "spam_probability": spam_probability,
        "label": "spam" if spam_probability >= 0.5 else "ham"
    })

@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.environ.get("PORT", 5000)))